import org.junit.jupiter.api.Test

/**
 * Tests for issue https://github.com/pinterest/ktlint/issues/1756
 * Format parameters in lambda when the trailing lambda follows a multiline call expression
 */
class IndentationRuleIssue1756Test {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with multiline parameters following a multiline call expression` {
        private val code =
            """
            fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                c(a, b)
            }

            class Foo {
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                        b ->
                        TODO()
                    }
                }
            }
            """.trimIndent()

        @Test
        fun `Given ktlint_official code style`() {
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style`() {
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given android_studio code style`() {
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.android_studio)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with single line parameters and the first on same line as brace` {
        @Test
        fun `Given ktlint_official code style and lambda parameters on same line as brace then expect double indent`() {
            val code =
                """
                fun foo() {
                    combine(Any(), Any()) { a,
                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style and lambda parameters on same line as brace then expect alignment with first parameter`() {
            // In intellij_idea style, lambda parameters should be aligned with the first parameter
            // when the first parameter is on the same line as the opening brace
            val code =
                """
                fun foo() {
                    combine(Any(), Any()) { a,
                                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with parameters starting on new line` {
        @Test
        fun `Given any code style with lambda parameters starting on new line after brace then expect double indent`() {
            val code =
                """
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) {
                            a,
                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }
    }
}
