import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Nested
import org.junit.jupiter.api.Test

/**
 * Tests for issue https://github.com/pinterest/ktlint/issues/1756
 * Format parameters in lambda when the trailing lambda follows a multiline call expression
 */
class IndentationRuleIssue1756Test {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with multiline parameters following a multiline call expression` {
        @Test
        fun `Given ktlint_official code style with trailing lambda following multiline call then expect double indent for lambda params`() {
            val code =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                    c(a, b)
                }

                class Foo {
                    fun foo() {
                        combine(
                            Any(),
                            Any()
                        ) { a,
                                b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style with trailing lambda following multiline call then expect double indent for lambda params`() {
            // When the call expression before the trailing lambda is multiline, the alignment with
            // the function name does not make sense. In this case, double indent should be used.
            val code =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                    c(a, b)
                }

                class Foo {
                    fun foo() {
                        combine(
                            Any(),
                            Any()
                        ) { a,
                                b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }

        @Test
        fun `Given android_studio code style with trailing lambda following multiline call then expect double indent for lambda params`() {
            val code =
                """
                fun combine(a: Any, b: Any, c: (Any, Any) -> Unit) {
                    c(a, b)
                }

                class Foo {
                    fun foo() {
                        combine(
                            Any(),
                            Any()
                        ) { a,
                                b ->
                            TODO()
                        }
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.android_studio)
                .hasNoLintViolations()
        }

        @Test
        fun `Given badly indented code with trailing lambda following multiline call then fix the indentation`() {
            val code =
                """
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                        b ->
                        TODO()
                    }
                }
                """.trimIndent()
            val formattedCode =
                """
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) { a,
                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasLintViolation(6, 1, "Unexpected indentation (8) (should be 12)")
                .isFormattedAs(formattedCode)
        }
    }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with single line call expression before it` {
        @Test
        fun `Given ktlint_official code style and lambda parameters on same line as brace then expect double indent`() {
            val code =
                """
                fun foo() {
                    combine(Any(), Any()) { a,
                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.ktlint_official)
                .hasNoLintViolations()
        }

        @Test
        fun `Given intellij_idea code style and single line call with lambda params on same line as brace then expect alignment`() {
            // In intellij_idea style with a single line call expression, lambda parameters should be 
            // aligned with the first parameter when the first parameter is on the same line as 
            // the opening brace
            val code =
                """
                fun foo() {
                    combine(Any(), Any()) { a,
                                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }
    }

    @Nested
    inner class `Issue 1756 - Given a trailing lambda with parameters starting on new line` {
        @Test
        fun `Given any code style with lambda parameters starting on new line after brace then expect double indent`() {
            val code =
                """
                fun foo() {
                    combine(
                        Any(),
                        Any()
                    ) {
                            a,
                            b ->
                        TODO()
                    }
                }
                """.trimIndent()
            indentationRuleAssertThat(code)
                .withEditorConfigOverride(CODE_STYLE_PROPERTY to CodeStyleValue.intellij_idea)
                .hasNoLintViolations()
        }
    }
