    }", "new_string": "    /**
     * Checks whether this node is part of a trailing lambda which follows a multiline call expression.
     * For example:
     * ```kotlin
     * combine(
     *     Any(),
     *     Any()
     * ) { a,
     *     b ->
     *     TODO()
     * }
     * ```
     * In this case, the lambda parameters should use double indent instead of alignment to the function name.
     */
    private fun ASTNode.isTrailingLambdaWithMultiLineCallExpressionBeforeLambdaArgument(): Boolean {
        val functionLiteral = parent(FUNCTION_LITERAL)
        if (functionLiteral == null) {
            LOGGER.debug { "isTrailingLambda: functionLiteral is null" }
            return false
        }
        val lambdaArgument = functionLiteral.treeParent?.takeIf { it.elementType == LAMBDA_ARGUMENT }
        if (lambdaArgument == null) {
            LOGGER.debug { "isTrailingLambda: lambdaArgument is null, parent type = ${functionLiteral.treeParent?.elementType}" }
            return false
        }
        val callExpression = lambdaArgument.treeParent?.takeIf { it.elementType == CALL_EXPRESSION }
        if (callExpression == null) {
            LOGGER.debug { "isTrailingLambda: callExpression is null, parent type = ${lambdaArgument.treeParent?.elementType}" }
            return false
        }
        // Check if the VALUE_ARGUMENT_LIST (containing the regular arguments before the trailing lambda) 
        // contains newlines, indicating a multiline call expression
        val valueArgList = callExpression.findChildByType(VALUE_ARGUMENT_LIST)
        val hasNewline = valueArgList?.textContains('\n') == true
        LOGGER.debug { "isTrailingLambda: valueArgList found=${valueArgList != null}, hasNewline=$hasNewline" }
        return hasNewline
    }"}

