        if (codeStyle == ktlint_official || isFirstParameterOfFunctionLiteralPrecededByNewLine()) {
            // val fieldExample =
            //      LongNameClass {
            //              paramA,
            //              paramB,
            //              paramC ->
            //          ClassB(paramA, paramB, paramC)
            //      }
            return indentConfig.indent.repeat(2)
        }

        // Check if this is a trailing lambda where the call expression before the lambda contains newlines.
        // In this case, alignment to the function name doesn't make sense visually.
        // For example:
        //     combine(
        //         Any(),
        //         Any()
        //     ) { a,
        //             b ->  // Should use double indent, not align to "combine { "
        //         TODO()
        //     }
        val functionLiteral = parent(FUNCTION_LITERAL)
        val lambdaArgument = functionLiteral?.treeParent?.takeIf { it.elementType == LAMBDA_ARGUMENT }
        val callExpression = lambdaArgument?.treeParent?.takeIf { it.elementType == CALL_EXPRESSION }
        if (callExpression != null) {
            val valueArgumentList = callExpression.findChildByType(VALUE_ARGUMENT_LIST)
            if (valueArgumentList?.textContains('\n') == true) {
                return indentConfig.indent.repeat(2)
            }
        }

        // Allow default IntelliJ IDEA formatting:
        // val fieldExample =
        //     LongNameClass { paramA,
        //                     paramB,
        //                     paramC ->
        //         ClassB(paramA, paramB, paramC)
        //     }
        return parent(CALL_EXPRESSION)
            ?.let { callExpression ->
                val textBeforeFirstParameter =
                    callExpression.findChildByType(REFERENCE_EXPRESSION)?.text +
                        " { "
                " ".repeat(textBeforeFirstParameter.length)
            }
            ?: indentConfig.indent.repeat(2)
    }"}

